"use client";

import { useParams } from "next/navigation";
import { useEffect, useState } from "react";
import { apiRequest } from "@/lib/api";
import { useAuth } from "@/context/AuthContext";
import toast from "react-hot-toast";

export default function ProductDetailPage() {
  const { id } = useParams<{ id: string }>();
  const { token } = useAuth();

  const [product, setProduct] = useState<any>(null);
  const [quantity, setQuantity] = useState(1);
  const [customTexts, setCustomTexts] = useState<string[]>([""]);

  useEffect(() => {
    apiRequest(`/products/${id}`).then(setProduct);
  }, [id]);

  useEffect(() => {
    setCustomTexts(Array.from({ length: quantity }, () => ""));
  }, [quantity]);

  const handleAddToCart = async () => {
    if (!token) {
      toast.error("Please login first");
      return;
    }

    await apiRequest(
      "/cart/add",
      "POST",
      {
        productId: product.id,
        productName: product.name,
        price: product.price,
        quantity,
        customTexts,
      },
      token
    );

    toast.success("Added to cart");
  };

  if (!product) {
    return (
      <main className="px-6 py-32 text-center opacity-70">
        Loading product…
      </main>
    );
  }

  return (
    <main className="px-6 py-32 max-w-6xl mx-auto grid lg:grid-cols-2 gap-16">

      {/* LEFT — IMAGES */}
      <div>
        <div className="
          bg-[var(--color-blush)]
          border border-[var(--color-rose)]
          rounded-xl
          p-4
          mb-6
        ">
          <img
            src={product.images[0]}
            alt={product.name}
            className="w-full h-[420px] object-cover rounded-lg"
          />
        </div>

        <div className="grid grid-cols-3 gap-4">
          {product.images.map((img: string, i: number) => (
            <img
              key={i}
              src={img}
              alt=""
              className="
                aspect-square
                object-cover
                rounded-lg
                border border-[var(--color-rose)]
              "
            />
          ))}
        </div>
      </div>

      {/* RIGHT — DETAILS */}
      <div>
        <h1 className="font-[var(--font-serif)] text-5xl mb-4">
          {product.name}
        </h1>

        <p className="text-xl mb-8">
          ₹{product.price}
        </p>

        {/* QUANTITY */}
        <div className="mb-8">
          <label className="block text-sm mb-2 opacity-80">
            Quantity
          </label>

          <div className="inline-flex items-center border border-[var(--color-rose)] rounded overflow-hidden bg-white/60">

            {/* MINUS */}
            <button
              type="button"
              onClick={() => setQuantity((q) => Math.max(1, q - 1))}
              disabled={quantity === 1}
              className="
                px-4 py-2
                text-lg
                disabled:opacity-40
                hover:bg-[var(--color-blush)]
                transition
              "
            >
              −
            </button>

            {/* NUMBER */}
            <input
              type="number"
              min={1}
              value={quantity}
              onChange={(e) =>
                setQuantity(Math.max(1, Number(e.target.value)))
              }
              className="
                w-16
                text-center
                bg-transparent
                outline-none
                text-sm
              "
            />

            {/* PLUS */}
            <button
              type="button"
              onClick={() => setQuantity((q) => q + 1)}
              className="
                px-4 py-2
                text-lg
                hover:bg-[var(--color-blush)]
                transition
              "
            >
              +
            </button>
          </div>
        </div>

        {/* CUSTOM TEXTS */}
        <div className="mb-10 space-y-4">
          <h2 className="text-sm opacity-80">
            Custom text (one per item)
          </h2>

          {customTexts.map((t, i) => (
            <input
              key={i}
              placeholder={`Custom text ${i + 1}`}
              value={t}
              onChange={(e) => {
                const copy = [...customTexts];
                copy[i] = e.target.value;
                setCustomTexts(copy);
              }}
              className="
                w-full
                p-3
                border border-[var(--color-rose)]
                bg-white/60
                rounded
                focus:outline-none
                focus:border-[var(--color-accent)]
              "
            />
          ))}
        </div>

        {/* CTA */}
        <button
          onClick={handleAddToCart}
          className="
            bg-[var(--color-accent)]
            text-white
            px-12 py-3
            uppercase tracking-widest text-sm
            hover:opacity-90
            transition
          "
        >
          Add to Cart
        </button>
      </div>
    </main>
  );
}